import api from './app/client';

import type { UpdateWorkDayPayload, ImportWorkSchedulePayload } from '../types/dto';
import type { WorkScheduleResponse } from '../types/work-schedule';
import { WorkScheduleResponseSchema } from '../types/schemas';

export type { UpdateWorkDayPayload, ImportWorkSchedulePayload, WorkScheduleResponse };

export const workScheduleService = {
  getWorkSchedule: (year: number, month: number): Promise<WorkScheduleResponse> =>
    api.get('/work-schedule/my', { params: { year, month } })
      .then(r => WorkScheduleResponseSchema.parse(r.data)),

  updateWorkDay: (payload: UpdateWorkDayPayload) =>
    api.put('/work-schedule/day', payload).then(r => r.data),

  submitSchedule: (monthId: string) =>
    api.post(`/work-schedule/${monthId}/submit`).then(r => r.data),

  approveSchedule: (monthId: string) =>
    api.post(`/work-schedule/${monthId}/approve`).then(r => r.data),

  rejectSchedule: (monthId: string, notes: string) =>
    api.post(`/work-schedule/${monthId}/reject`, { notes }).then(r => r.data),

  importWorkSchedule: (payload: ImportWorkSchedulePayload) =>
    api.post('/work-schedule/import', payload).then(r => r.data),

  importWeek: (payload: any) =>
    api.post('/work-schedule/import/week', payload).then(r => r.data),

  clearWorkSchedule: (monthId: string) =>
    api.post(`/work-schedule/${monthId}/clear`).then(r => r.data),

  unfreezeSchedule: (monthId: string) =>
    api.post(`/work-schedule/${monthId}/unfreeze`).then(r => r.data),

  // Admin only
  getPendingSchedulesForApproval: () =>
    api.get('/work-schedule/pending-approval').then(r => r.data),

  // Admin only - get all team members' schedules for a month
  getTeamSchedules: (year: number, month: number): Promise<WorkScheduleResponse[]> =>
    api.get<WorkScheduleResponse[]>('/work-schedule/team', { params: { year, month } }).then(r => r.data),

  getAllSchedules: (year: number, month: number): Promise<WorkScheduleResponse[]> =>
    api.get<WorkScheduleResponse[]>('/work-schedule/all', { params: { year, month } }).then(r => r.data),
};
